const raw =
  $json.output ??
  $json.text ??
  $json.response ??
  $json;

function normalizeResponse(value) {
  if (typeof value === 'object' && value !== null) return value;
  if (typeof value !== 'string') return null;

  let cleaned = value.trim();

  // Remove bloco ```json ... ```
  cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '');
  cleaned = cleaned.replace(/\s*```$/i, '').trim();

  // Tenta parsear JSON limpo
  try {
    return JSON.parse(cleaned);
  } catch (e) {
    return null;
  }
}

const parsed = normalizeResponse(raw);

if (parsed && typeof parsed === 'object') {
  return [{
    json: {
      text: typeof parsed.text === 'string' ? parsed.text : 'Resposta processada.',
      actions: Array.isArray(parsed.actions) ? parsed.actions : []
    }
  }];
}

if (typeof raw === 'string') {
  return [{
    json: {
      text: raw,
      actions: []
    }
  }];
}

return [{
  json: {
    text: 'Não foi possível processar a resposta do agente.',
    actions: []
  }
}];

// Pega os dados exatos que chegaram NESTA iteração do loop
const inputData = $input.all()[0].json;

// O n8n às vezes repassa o erro embrulhado no cabo vermelho (Error Output).
// Essa lógica garante que vamos achar suas variáveis onde quer que estejam:
let promptAtual = inputData.prompt || (inputData.item && inputData.item.prompt);
let sessionIdAtual = inputData.sessionId || (inputData.item && inputData.item.sessionId);
let chavesAtuais = inputData.chavesDisponiveis || (inputData.item && inputData.item.chavesDisponiveis);

// Se por algum motivo catastrófico o nó de erro destruir o array, paramos por aqui para evitar loop infinito
if (!chavesAtuais || !Array.isArray(chavesAtuais)) {
    return [{
        json: {
            chavesDisponiveis: [],
            text: JSON.stringify({
                text: "Erro Operacional Crítico: Perda do array de chaves durante o loop de fallback.",
                actions: []
            })
        }
    }];
}

// Remove fisicamente a chave que acabou de falhar (a que estava no índice 0)
if (chavesAtuais.length > 0) {
    chavesAtuais.shift();
}

// Condição de parada: Array exauriu (todas as 5 ou 6 contas deram Rate Limit)
if (chavesAtuais.length === 0) {
    return [{
        json: {
            prompt: promptAtual,
            sessionId: sessionIdAtual,
            chavesDisponiveis: [], // Array vazio sinaliza para um possível nó IF parar o loop
            text: JSON.stringify({
                text: "Erro Operacional: O tráfego estourou a cota de tokens (TPM/TPD) de todas as contas em sequência. Aguarde 60 segundos.",
                actions: []
            })
        }
    }];
}

// Retorna o payload reestruturado. A próxima chave virou o índice [0].
return [{
    json: {
        prompt: promptAtual,
        sessionId: sessionIdAtual,
        chavesDisponiveis: chavesAtuais
    }
}];
